code.JavaScript:
function romanToInt(s) {
    let result = 0;
    const n = s.length;

    const romanValue = (c) => {
        switch(c) {
            case 'I': return 1;
            case 'V': return 5;
            case 'X': return 10;
            case 'L': return 50;
            case 'C': return 100;
            case 'D': return 500;
            case 'M': return 1000;
            default: return 0;
        }
    };

    for (let i = 0; i < n; i++) {
        let current = romanValue(s[i]);
        let next = (i + 1 < n) ? romanValue(s[i + 1]) : 0;

        if (current < next) {
            result -= current;
        } else {
            result += current;
        }
    }

    return result;
}
